import network
import socket
import ubinascii
import uhashlib
import struct
import json
import time
from machine import Pin

class WebSocketServer:
    def __init__(self, port=80):
        self.port = port
        self.server_socket = None
        self.clients = []
        self.led = Pin(2, Pin.OUT)
        self.device_state = {"led": False, "status": "ready"}
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('0.0.0.0', self.port))
        self.server_socket.listen(5)
        self.server_socket.setblocking(False)
        print(f"WebSocket server started on port {self.port}")
        
    def accept_connection(self):
        try:
            client_socket, addr = self.server_socket.accept()
            client_socket.setblocking(False)
            print(f"New connection from {addr}")
            return client_socket, addr
        except OSError:
            return None, None
            
    def handshake(self, client_socket):
        try:
            request = client_socket.recv(1024).decode('utf-8')
            
            if 'Upgrade: websocket' not in request:
                response = b"HTTP/1.1 200 OK\r\nContent-Type: text/html\r\n\r\n"
                response += b"<html><body><h1>ESP32 WebSocket Server</h1>"
                response += b"<script>"
                response += b"var ws = new WebSocket('ws://' + location.host);"
                response += b"ws.onopen = function() { console.log('Connected'); document.getElementById('status').innerText = 'Connected'; };"
                response += b"ws.onmessage = function(e) { console.log('Received:', e.data); document.getElementById('response').innerText = e.data; };"
                response += b"ws.onerror = function(e) { console.log('Error:', e); };"
                response += b"ws.onclose = function() { console.log('Disconnected'); document.getElementById('status').innerText = 'Disconnected'; };"
                response += b"function sendCommand(action) { ws.send(JSON.stringify({action: action})); }"
                response += b"</script>"
                response += b"<p>Status: <span id='status'>Disconnected</span></p>"
                response += b"<button onclick=\"sendCommand('turn_on')\">Turn ON</button>"
                response += b"<button onclick=\"sendCommand('turn_off')\">Turn OFF</button>"
                response += b"<button onclick=\"sendCommand('status')\">Get Status</button>"
                response += b"<p>Response: <span id='response'></span></p>"
                response += b"</body></html>"
                client_socket.send(response)
                client_socket.close()
                return False
                
            key = None
            for line in request.split('\r\n'):
                if line.startswith('Sec-WebSocket-Key:'):
                    key = line.split(': ')[1].strip()
                    break
                    
            if not key:
                client_socket.close()
                return False
                
            magic = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
            accept_key = ubinascii.b2a_base64(
                uhashlib.sha1((key + magic).encode()).digest()
            ).decode().strip()
            
            response = 'HTTP/1.1 101 Switching Protocols\r\n'
            response += 'Upgrade: websocket\r\n'
            response += 'Connection: Upgrade\r\n'
            response += f'Sec-WebSocket-Accept: {accept_key}\r\n\r\n'
            
            client_socket.send(response.encode())
            return True
            
        except Exception as e:
            print(f"Handshake error: {e}")
            try:
                client_socket.close()
            except:
                pass
            return False
            
    def parse_frame(self, data):
        if len(data) < 2:
            return None
            
        byte1 = data[0]
        byte2 = data[1]
        
        fin = (byte1 & 0x80) >> 7
        opcode = byte1 & 0x0F
        
        masked = (byte2 & 0x80) >> 7
        payload_length = byte2 & 0x7F
        
        offset = 2
        
        if payload_length == 126:
            if len(data) < 4:
                return None
            payload_length = struct.unpack('>H', data[2:4])[0]
            offset = 4
        elif payload_length == 127:
            if len(data) < 10:
                return None
            payload_length = struct.unpack('>Q', data[2:10])[0]
            offset = 10
            
        if masked:
            if len(data) < offset + 4:
                return None
            mask = data[offset:offset+4]
            offset += 4
        else:
            mask = None
            
        if len(data) < offset + payload_length:
            return None
            
        payload = bytearray(data[offset:offset+payload_length])
        
        if mask:
            for i in range(len(payload)):
                payload[i] ^= mask[i % 4]
                
        return {
            'fin': fin,
            'opcode': opcode,
            'payload': payload,
            'length': offset + payload_length
        }
        
    def create_frame(self, payload, opcode=1):
        frame = bytearray()
        
        frame.append(0x80 | opcode)
        
        payload_bytes = payload.encode() if isinstance(payload, str) else payload
        payload_length = len(payload_bytes)
        
        if payload_length < 126:
            frame.append(payload_length)
        elif payload_length < 65536:
            frame.append(126)
            frame.extend(struct.pack('>H', payload_length))
        else:
            frame.append(127)
            frame.extend(struct.pack('>Q', payload_length))
            
        frame.extend(payload_bytes)
        return bytes(frame)
        
    def handle_command(self, command_str):
        try:
            command = json.loads(command_str)
            action = command.get('action', '')
            
            if action == 'turn_on':
                self.led.value(1)
                self.device_state['led'] = True
                return json.dumps({"status": "success", "action": "turn_on", "led": True})
                
            elif action == 'turn_off':
                self.led.value(0)
                self.device_state['led'] = False
                return json.dumps({"status": "success", "action": "turn_off", "led": False})
                
            elif action == 'status':
                return json.dumps({"status": "success", "state": self.device_state})
                
            elif action == 'toggle':
                new_state = not self.device_state['led']
                self.led.value(new_state)
                self.device_state['led'] = new_state
                return json.dumps({"status": "success", "action": "toggle", "led": new_state})
                
            else:
                return json.dumps({"status": "error", "message": "Unknown action"})
                
        except Exception as e:
            return json.dumps({"status": "error", "message": str(e)})
            
    def handle_client(self, client_socket):
        try:
            data = client_socket.recv(1024)
            if not data:
                return False
                
            frame = self.parse_frame(data)
            if not frame:
                return True
                
            if frame['opcode'] == 8:
                print("Client requested close")
                return False
                
            if frame['opcode'] == 9:
                pong_frame = self.create_frame(frame['payload'], opcode=10)
                client_socket.send(pong_frame)
                return True
                
            if frame['opcode'] == 1:
                message = frame['payload'].decode('utf-8')
                print(f"Received: {message}")
                
                response = self.handle_command(message)
                response_frame = self.create_frame(response)
                client_socket.send(response_frame)
                
            return True
            
        except OSError as e:
            if e.args[0] == 11:
                return True
            print(f"Client error: {e}")
            return False
        except Exception as e:
            print(f"Error handling client: {e}")
            return False
            
    def run(self):
        self.start()
        
        while True:
            client_socket, addr = self.accept_connection()
            if client_socket:
                if self.handshake(client_socket):
                    self.clients.append(client_socket)
                    print(f"WebSocket connection established with {addr}")
                    
            clients_to_remove = []
            for client in self.clients:
                if not self.handle_client(client):
                    clients_to_remove.append(client)
                    
            for client in clients_to_remove:
                try:
                    client.close()
                except:
                    pass
                self.clients.remove(client)
                print("Client disconnected")
                
            time.sleep(0.01)

def connect_wifi(ssid, password):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print('Connecting to WiFi...')
        wlan.connect(ssid, password)
        while not wlan.isconnected():
            time.sleep(1)
    print('Network config:', wlan.ifconfig())
    return wlan.ifconfig()[0]

